def brun_rule(m, p, s, t):
    s_list = list(m.s); t_list = list(m.t)
    si = s_list.index(s); ti = t_list.index(t)
    rhs = 0
    if si > 0:
        rhs += m.b[p, s_list[si - 1], t] - m.e[p, s_list[si - 1], t]
    if ti > 0:
        rhs += m.e[p, s, t_list[ti - 1]]
    if (not ti) and (not si):
        rhs += 1
    return m.b[p, s, t] == rhs
model.brun = Constraint(model.p, model.s, model.t, rule=brun_rule)

